#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char S[N + 1];
        scanf("%s", S);
        int maxPower = -1000000;
        for (int mask = 0; mask < (1 << N); mask++) {
            int power = 0;
            int sum = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) == 0) {
                    power++;
                } else {
                    sum += S[i] - 'a' + 1;
                    power--;
                }
            }
            power += sum / (double)K;
            if (power > maxPower) {
                maxPower = power;
            }
        }
        int a = maxPower * K;
        int b = K;
        int g = gcd(a, b);
        printf("%d %d\n", a / g, b / g);
    }
    return 0;
}

