import math

def gcd(a, b):
    if b == 0: return a
    return gcd(b, a % b)

def main():
    T = int(input())
    for _ in range(T):
        N, K = map(int, input().split())
        S = input()
        maxPower = -1000000
        for mask in range(1 << N):
            power = 0
            sum = 0
            for i in range(N):
                if (mask & (1 << i)) == 0:
                    power += 1
                else:
                    sum += ord(S[i]) - ord('a') + 1
                    power -= 1
            power += sum / K
            if power > maxPower:
                maxPower = power
        a = int(maxPower * K)
        b = K
        g = gcd(a, b)
        print(a // g, b // g)

def solve():
    main()
